function example() {
  if (true) {
    var x = 1;    // ← var 声明在 if 里
  }
  console.log(x); // 1 ✅ 居然能在 if 外面访问！
}
// var 的作用域是整个函数，不是 if 块

function example() {
  if (true) {
    let a = 1;      // ← let 声明在 if 里
    const b = 2;    // ← const 声明在 if 里
  }
  // a, b 在这里已经销毁了
  console.log(a);  // ❌ ReferenceError: a is not defined
}

// TDZ（Temporal Dead Zone，暂时性死区）
// 从作用域开始到声明语句之间，变量存在但"禁止访问"

console.log(y);  // ❌ ReferenceError!
let y = 5;       // ← 声明点，TDZ 结束
console.log(y);  // 5 ✅ 安全访问

var name = "Alice";
var name = "Bob";    // ✅ 不报错！静默覆盖了前面的 name
console.log(name);   // "Bob"
// 你可能根本不知道 name 被覆盖了

let name = "Alice";
let name = "Bob";    // ❌ SyntaxError: Identifier 'name' has already been declared

const PI = 3.14;
const PI = 3.14;    // ❌ 同样报错

const API_URL = "https://api.example.com";
API_URL = "https://other.com";  // ❌ TypeError: Assignment to constant variable

const MAX = 100;
MAX = 200;  // ❌ 同样报错

for (var i = 0; i < 3; i++) {
  setTimeout(() => {
    console.log(i);  // 3, 3, 3  ← 不是 0, 1, 2！
  }, 100);
}
// 原因：var i 是函数作用域，3 次循环共用同一个 i
// 循环结束时 i = 3，3 个回调都读到 3

for (let i = 0; i < 3; i++) {
  setTimeout(() => {
    console.log(i);  // 0, 1, 2  ✅
  }, 100);
}
// 原因：let i 是块级作用域，每次循环创建一个新的 i
// 3 个回调各自"记住"自己的 i
